import{_ as n,o as s,c as a,ae as i,j as e}from"./chunks/framework.CyZiF_rV.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"en/limity/limity-api.md","filePath":"en/limity/limity-api.md"}'),o={name:"en/limity/limity-api.md"};function r(l,t,d,c,h,u){return s(),a("div",null,[...t[0]||(t[0]=[i(`<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/limity/limity-api.md" target="_blank" rel="noreferrer">limity/limity-api.md</a></p></blockquote><h2 id="api-request-limits" tabindex="-1">API Request Limits <a class="header-anchor" href="#api-request-limits" aria-label="Permalink to &quot;API Request Limits&quot;">​</a></h2><p>22.11.2025</p><p>Due to the scale of KSeF operations and its public nature, mechanisms have been introduced to limit the intensity of API requests. Their purpose is to protect system stability, protect against cyber threats, and ensure equal access conditions for all users. The limits define the maximum number of queries that can be executed within a specified time and enforce an integration approach that aligns with the system&#39;s architectural assumptions.</p><h3 id="general-principles-of-limits" tabindex="-1">General Principles of Limits <a class="header-anchor" href="#general-principles-of-limits" aria-label="Permalink to &quot;General Principles of Limits&quot;">​</a></h3><h4 id="_1-how-limits-are-calculated" tabindex="-1">1. How Limits Are Calculated <a class="header-anchor" href="#_1-how-limits-are-calculated" aria-label="Permalink to &quot;1. How Limits Are Calculated&quot;">​</a></h4><p>All requests to the KSeF API are subject to limits. These restrictions apply to every call to a protected endpoint. For traffic billing purposes, requests are grouped by pair: context and IP address.</p><ul><li><strong>context</strong> - defined by the <code>ContextIdentifier</code> (<code>Nip</code>, <code>InternalId</code>, or <code>NipVatUe</code>) passed during authentication.</li><li><strong>IP address</strong> - the IP address from which the network connection is established.</li></ul><p>Request limits are calculated independently for each pair: context and IP address. This means that traffic in the same context but from different IP addresses is billed separately.</p><p>Example<br> Accounting firm A downloads invoices on behalf of company B, using company B&#39;s context (NIP) and connecting to KSeF from IP address IP1. Simultaneously, company B downloads invoices independently, in the same context (its own NIP), but from a different IP address - IP2. Despite the shared context, different IP addresses cause limits to be calculated independently. In such a situation, the system treats each connection as a separate pair (context + IP address) and calculates limits independently: separately for accounting firm A and separately for company B.</p><p><strong>Limit Units</strong><br> The following notations are used in limit tables:</p><ul><li>req/s - number of requests per second,</li><li>req/min - number of requests per minute,</li><li>req/h - number of requests per hour.</li></ul><p><strong>Limit Calculation Model (sliding/rolling window)</strong><br> Limits are enforced using a sliding time window model. At any given moment, requests executed in the following periods are counted:</p><ul><li>for req/h threshold - in the last 60 minutes,</li><li>for req/min threshold - in the last 60 seconds,</li><li>for req/s threshold - in the last second.</li></ul><p>Windows are not aligned to full hours or minutes (they do not &quot;reset&quot; at :00). All thresholds (req/s, req/min, req/h) apply concurrently - blocking is triggered upon the first violation of any of them.</p><h4 id="_2-system-blocks-api-access-after-limit-exceeded" tabindex="-1">2. System Blocks API Access After Limit Exceeded <a class="header-anchor" href="#_2-system-blocks-api-access-after-limit-exceeded" aria-label="Permalink to &quot;2. System Blocks API Access After Limit Exceeded&quot;">​</a></h4><p>When API request limits are exceeded, HTTP code <strong>429 Too Many Requests</strong> is returned, and subsequent requests are temporarily blocked.<br> The blocking period is <strong>dynamic</strong> and depends on the frequency and scale of violations. The exact blocking time is returned in the <code>Retry-After</code> response header (in seconds). Multiple violations can result in significantly extended blocking periods.</p><p>Example 429 response:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">HTTP/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 429</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Too Many Requests</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Content-Type: application/json</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Retry-After: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;code&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">429</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Too Many Requests&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;details&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Exceeded limit of 20 requests per minute. Try again after 30 seconds.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h4 id="_3-recording-violations" tabindex="-1">3. Recording Violations <a class="header-anchor" href="#_3-recording-violations" aria-label="Permalink to &quot;3. Recording Violations&quot;">​</a></h4><p>All cases of request limit violations are logged and analyzed by security mechanisms. This data is used to monitor API stability and detect potential abuse. The system pays particular attention to patterns indicating attempts to circumvent limits, e.g., through parallel and systematic use of multiple IP addresses within one context. Such actions may be considered a security threat.</p><p>In case of repeated violations or extreme load, the system may automatically apply protective measures, such as:</p><ul><li>blocking access to the KSeF API for a given entity or IP address range,</li><li>limiting availability for the most burdensome contexts.</li></ul><h4 id="_4-higher-limits-during-night-hours" tabindex="-1">4. Higher Limits During Night Hours <a class="header-anchor" href="#_4-higher-limits-during-night-hours" aria-label="Permalink to &quot;4. Higher Limits During Night Hours&quot;">​</a></h4><p>Between 20:00-06:00, higher download limits apply than during the day. Detailed values will be determined in the initial period of KSeF 2.0 operation, after adjusting parameters to actual loads.</p><h4 id="_5-preliminary-limit-assumptions" tabindex="-1">5. Preliminary Limit Assumptions <a class="header-anchor" href="#_5-preliminary-limit-assumptions" aria-label="Permalink to &quot;5. Preliminary Limit Assumptions&quot;">​</a></h4><p>API request limits have been determined based on anticipated system usage scenarios and load models.</p><p>The actual nature of traffic will depend on how integrations are implemented in external systems and the load patterns they generate. This means that limits established at the design stage may differ from values maintained in the production environment.</p><p>For this reason, limits are dynamic in nature and may be adjusted depending on operational conditions and integrator behavior. In particular, their temporary reduction is permitted in case of intensive or inefficient API usage.</p><h3 id="limits-in-environments" tabindex="-1">Limits in Environments <a class="header-anchor" href="#limits-in-environments" aria-label="Permalink to &quot;Limits in Environments&quot;">​</a></h3><p><strong>TE (Test) Environment</strong> In the TE environment, limits have been configured to allow integrators to work freely and test integrations without risk of blocking. Default limit values are <strong>ten times higher</strong> than in production, allowing for intensive testing. Additionally, thanks to available endpoints, various scenarios can be simulated:</p><ul><li><a href="https://api-test.ksef.mf.gov.pl/docs/v2/index.html#tag/Limity-i-ograniczenia/paths/~1testdata~1rate-limits~1production/post" target="_blank" rel="noreferrer">POST /testdata/rate-limits/production</a> - activates limits as in production (PRD),</li><li><a href="https://api-test.ksef.mf.gov.pl/docs/v2/index.html#tag/Limity-i-ograniczenia/paths/~1testdata~1rate-limits/post" target="_blank" rel="noreferrer">POST /testdata/rate-limits</a> - allows setting custom values,</li><li><a href="https://api-test.ksef.mf.gov.pl/docs/v2/index.html#tag/Limity-i-ograniczenia/paths/~1testdata~1rate-limits/delete" target="_blank" rel="noreferrer">DELETE /testdata/rate-limits</a> - restores default TE environment limits.</li></ul><p><strong>DEMO (Pre-production) Environment</strong> In the DEMO environment, <strong>the same limits as in production</strong> apply for a given context. These values are <strong>replicated from PRD</strong> and serve for final validation of performance and integration stability before production deployment.</p><p><strong>PRD (Production) Environment</strong> In the PRD environment, <strong>default limits</strong> specified in this documentation are applied. In justified cases - e.g., large-scale invoice processing - there is a possibility to <strong>submit a request for limit increase</strong> via a dedicated form (in preparation).</p><h2 id="invoice-download-limits" tabindex="-1">Invoice Download - Limits <a class="header-anchor" href="#invoice-download-limits" aria-label="Permalink to &quot;Invoice Download - Limits&quot;">​</a></h2><h3 id="architectural-assumptions" tabindex="-1">Architectural Assumptions <a class="header-anchor" href="#architectural-assumptions" aria-label="Permalink to &quot;Architectural Assumptions&quot;">​</a></h3><p>The KSeF API in the area of invoice downloading has been designed as a <strong>document synchronization</strong> mechanism between the central repository and the local database of external systems. The key assumption is that business operations, such as searching, filtering, or reporting, should be performed on locally stored data that has been previously synchronized with KSeF. This approach increases operational stability, minimizes the risk of system overload, and allows for more flexible data utilization by client applications.</p><p>The KSeF API in the scope of invoice downloading is not intended to handle direct real-time end-user operations. This means it should not be used for:</p><ul><li>downloading individual invoices on user demand, e.g., invoice preview,</li><li>downloading invoice metadata lists or initiating package exports in response to current application actions, except when the user consciously initiates data synchronization.</li></ul><h3 id="recommended-integration-approach-for-downloads" tabindex="-1">Recommended Integration Approach for Downloads <a class="header-anchor" href="#recommended-integration-approach-for-downloads" aria-label="Permalink to &quot;Recommended Integration Approach for Downloads&quot;">​</a></h3><p>The <code>/invoices/query/metadata</code> endpoint is used for incremental synchronization. Detailed rules for incremental synchronization are described in a separate document.</p><p>Depending on invoice volume, different approaches to downloading them can be used:</p><ol><li><strong>Low volume scenarios</strong> - if the number of invoices is limited and can be handled within available limits in the expected time, they can be downloaded synchronously by calling <code>/invoices/ksef/{ksefNumber}</code> for selected documents.</li><li><strong>High volume scenarios</strong> - if the number of documents is significant and handling in synchronous mode becomes impractical, it is recommended to use the export mechanism (<code>/invoices/exports</code>). Export works asynchronously, is queued, and therefore does not negatively impact system performance.</li><li><strong>Business operations</strong> - regardless of the chosen strategy, all user activities (searching, filtering, reporting) should be performed on the <strong>local database</strong>, previously synchronized with KSeF.</li></ol><h3 id="invoice-synchronization-and-download-modes" tabindex="-1">Invoice Synchronization and Download Modes <a class="header-anchor" href="#invoice-synchronization-and-download-modes" aria-label="Permalink to &quot;Invoice Synchronization and Download Modes&quot;">​</a></h3><p>Invoice download to an accounting system can be implemented in three modes:</p><ol><li><strong>On user demand</strong> - incremental synchronization is triggered <strong>manually</strong> by the user, from the last confirmed checkpoint.</li><li><strong>Cyclically</strong> - incremental synchronization is performed automatically according to the system schedule.</li><li><strong>Mixed mode</strong> - incremental synchronization runs cyclically, and additionally the user can trigger it manually on demand.</li></ol><h3 id="polling-frequency" tabindex="-1">Polling Frequency <a class="header-anchor" href="#polling-frequency" aria-label="Permalink to &quot;Polling Frequency&quot;">​</a></h3><ul><li><strong>High-frequency schedules are not recommended</strong>. In the production environment, the cyclic interval should not be shorter than 15 minutes for each entity appearing on the invoice (Entity 1, Entity 2, Entity 3, Authorized entity).</li><li><strong>Low volume profiles.</strong> On-demand downloading is recommended, supplemented by a cycle e.g., once a day in the night window.</li><li><strong>Invoice receipt date.</strong> The invoice receipt date is the date when the KSeF number is assigned. This number is automatically assigned by the system at the moment the invoice is processed and does not depend on when it is downloaded to the accounting system.</li></ul><h3 id="examples-of-non-recommended-implementation" tabindex="-1">Examples of Non-recommended Implementation <a class="header-anchor" href="#examples-of-non-recommended-implementation" aria-label="Permalink to &quot;Examples of Non-recommended Implementation&quot;">​</a></h3><p>Improper integration can lead to API blocking. The most common errors include:</p><ol><li>Synchronization exclusively through downloading individual invoices (synchronous path), without using invoice package export. Such an approach is permissible only in low volume profiles; with a larger number of documents, the <code>/invoices/exports</code> mechanism should be used.</li><li>Handling end-user requests (e.g., displaying full invoice content in the application, downloading XML file) through direct KSeF API calls instead of using the local database.</li></ol><h3 id="detailed-limits" tabindex="-1">Detailed Limits <a class="header-anchor" href="#detailed-limits" aria-label="Permalink to &quot;Detailed Limits&quot;">​</a></h3>`,52),e("table",{tabindex:"0"},[e("thead",null,[e("tr",null,[e("th",null,"Endpoint"),e("th"),e("th",null,"req/s"),e("th",null,"req/min"),e("th",null,"req/h")])]),e("tbody",null,[e("tr",null,[e("td",null,"Get invoice metadata list"),e("td",null,"POST /invoices/query/metadata"),e("td",null,"8"),e("td",null,"16"),e("td",null,"20")]),e("tr",null,[e("td",null,"Export invoice package"),e("td",null,"POST /invoices/exports"),e("td",null,"4"),e("td",null,"8"),e("td",null,"20")]),e("tr",null,[e("td",null,"Get export package status"),e("td",{referenceNumber:""},"/invoices/exports/"),e("td",null,"10"),e("td",null,"60"),e("td",null,"600")]),e("tr",null,[e("td",null,"Get invoice by KSeF number"),e("td",{ksefNumber:""},"GET /invoices/ksef/"),e("td",null,"8"),e("td",null,"16"),e("td",null,"64")])])],-1),i('<p><strong>Note:</strong> If the available invoice download limits are insufficient for your organization&#39;s business scenarios, please contact KSeF support for individual analysis and selection of an appropriate solution.</p><h2 id="invoice-sending-limits" tabindex="-1">Invoice Sending - Limits <a class="header-anchor" href="#invoice-sending-limits" aria-label="Permalink to &quot;Invoice Sending - Limits&quot;">​</a></h2><h3 id="architectural-assumptions-1" tabindex="-1">Architectural Assumptions <a class="header-anchor" href="#architectural-assumptions-1" aria-label="Permalink to &quot;Architectural Assumptions&quot;">​</a></h3><ul><li>Invoice sending, regardless of the type of sending, is queued.</li><li>Processing is optimized for the fastest possible confirmation of invoice correctness and return of the KSeF number.</li></ul><h4 id="batch-sending-invoice-packages" tabindex="-1">Batch Sending (invoice packages): <a class="header-anchor" href="#batch-sending-invoice-packages" aria-label="Permalink to &quot;Batch Sending (invoice packages):&quot;">​</a></h4><ul><li>An invoice package is treated as one message in the queue (package reference instead of separate entries for each invoice) and processed with the same priority as a single document.</li><li>Package sending reduces network and operational overhead because: <ul><li>fewer HTTP requests are executed,</li><li>content operations (decryption, validation, storage) are performed in batches, which is the most efficient way to handle multiple documents simultaneously.</li></ul></li><li>Batch compression. Due to the XML format and high repeatability of elements between invoices (fixed structure, similar field names, repeatable blocks), the achieved compression ratio is usually very favorable, which significantly reduces data volume and shortens transmission time. In practice, it is faster to send one package containing e.g., 100 invoices than 100 individual invoices in an interactive session.</li><li>Limits. The limit mechanism works independently of the sending mode. Batch sending naturally reduces the number of requests and facilitates efficient use of available limits.</li><li>Application. Batch mode is recommended wherever more than one document is transmitted in one operational window. It is particularly effective for cyclical customer settlements, in e-commerce, and in automated invoicing processes.</li></ul><p>Example scenarios for batch mode application:</p><ul><li><strong>Online store (e-commerce).</strong> Orders and payments are processed asynchronously, and invoices are issued automatically by the ERP system or invoicing module. A single invoice does not need to be sent to KSeF immediately after issuance. A dedicated process can aggregate issued invoices and cyclically - e.g., every 5 minutes - send them in batch packages to KSeF, which significantly reduces the number of HTTP requests and optimizes limit utilization.</li><li><strong>Subscription services / cyclical settlements.</strong> Invoices are generated collectively once a day or once a month (e.g., in telecommunications or media) and sent in one package within a planned batch session.</li><li><strong>Automated invoicing processes in enterprises.</strong> These occur e.g., in the distribution, logistics, production, or B2B service sectors. Invoices are generated automatically based on system events (deliveries, order fulfillments) and sent collectively, e.g., after operation completion.</li></ul><p><strong>Recommendation:</strong> to ensure maximum integration efficiency, it is recommended to aggregate documents in one batch session wherever possible from a business process perspective. This allows reducing the number of API requests and optimizes the use of available limits.</p><p><strong>Detailed Limits</strong></p><table tabindex="0"><thead><tr><th>Endpoint</th><th></th><th>req/s</th><th>req/min</th><th>req/h</th></tr></thead><tbody><tr><td>Open batch session *</td><td>POST /sessions/batch</td><td>10</td><td>20</td><td>60</td></tr><tr><td>Close batch session</td><td>POST /sessions/batch/{referenceNumber}/close</td><td>10</td><td>20</td><td>60</td></tr></tbody></table><p><strong>Package part sending</strong> - requests transmitting package parts within one batch session are not subject to API limits. For packages divided into multiple parts, parallel (multi-threaded) sending is recommended, which significantly shortens the sending time.</p><h4 id="interactive-sending-individual" tabindex="-1">Interactive Sending (individual) <a class="header-anchor" href="#interactive-sending-individual" aria-label="Permalink to &quot;Interactive Sending (individual)&quot;">​</a></h4><p>Interactive mode has been designed for scenarios requiring quick registration of individual invoices and immediate obtaining of the KSeF number. Unlike batch sessions, each invoice is sent independently within an active interactive session. Its purpose is to minimize the time needed to obtain the KSeF number for a single document. Application includes low volume scenarios where individual invoices are sent.</p><p>Example scenarios for interactive mode application:</p><ul><li><strong>Retail point of sale (POS)</strong>. After completing a transaction, an invoice is issued, and the system immediately registers it in KSeF and returns the KSeF number for printing or presentation to the customer.</li><li><strong>Mobile applications and lightweight sales systems</strong> that do not have queuing or buffering mechanisms, sending invoices immediately after issuance.</li><li><strong>One-time or irregular events</strong> e.g., a single corrective invoice.</li></ul><p>Interactive mode, despite greater network overhead in case of larger volumes, is a necessary complement to batch mode in scenarios requiring current response or immediate document registration in KSeF. It should be used exclusively where immediate invoice processing is crucial for the business process or when the scale of operations does not justify using batch sessions.</p><p><strong>Detailed Limits</strong></p><table tabindex="0"><thead><tr><th>Endpoint</th><th></th><th>req/s</th><th>req/min</th><th>req/h</th></tr></thead><tbody><tr><td>Open interactive session</td><td>POST /sessions/online</td><td>10</td><td>30</td><td>120</td></tr><tr><td>Send invoice *</td><td>POST /sessions/online/{referenceNumber}/invoices</td><td>10</td><td>30</td><td>180</td></tr><tr><td>Close interactive session</td><td>POST /sessions/online/{referenceNumber}/close</td><td>10</td><td>30</td><td>120</td></tr></tbody></table><p>* <strong>Note:</strong> If your organization&#39;s business scenarios regularly reach interactive session sending limits, batch mode should be considered first, which allows more efficient use of available resources and limits. In situations where using interactive sessions is necessary but the achieved limits remain insufficient, please contact KSeF support for individual analysis and help in selecting a solution.</p><h3 id="session-and-invoice-status" tabindex="-1">Session and Invoice Status <a class="header-anchor" href="#session-and-invoice-status" aria-label="Permalink to &quot;Session and Invoice Status&quot;">​</a></h3><p><strong>Detailed Limits</strong></p>',22),e("table",{tabindex:"0"},[e("thead",null,[e("tr",null,[e("th",null,"Endpoint"),e("th"),e("th",null,"req/s"),e("th",null,"req/min"),e("th",null,"req/h")])]),e("tbody",null,[e("tr",null,[e("td",null,"Get invoice status from session"),e("td",{invoiceReferenceNumber:""},"GET /sessions/{referenceNumber}/invoices/"),e("td",null,"30"),e("td",null,"120"),e("td",null,"1200")]),e("tr",null,[e("td",null,"Get session list"),e("td",null,"GET /sessions"),e("td",null,"5"),e("td",null,"10"),e("td",null,"60")]),e("tr",null,[e("td",null,"Get session invoices"),e("td",null,"GET /sessions/{referenceNumber}/invoices"),e("td",null,"10"),e("td",null,"20"),e("td",null,"200")]),e("tr",null,[e("td",null,"Get incorrectly processed session invoices"),e("td",null,"GET /sessions/{referenceNumber}/invoices/failed"),e("td",null,"10"),e("td",null,"20"),e("td",null,"200")]),e("tr",null,[e("td",null,"Others"),e("td",null,"GET /sessions/*"),e("td",null,"10"),e("td",null,"120"),e("td",null,"1200")])])],-1),i('<h2 id="others" tabindex="-1">Others <a class="header-anchor" href="#others" aria-label="Permalink to &quot;Others&quot;">​</a></h2><p>Default limits apply to all API resources that do not have specific values defined in this documentation. Each such endpoint has its own limit counter, and its requests do not affect other resources.</p><p>These limits apply only to protected resources. They do not include public API resources, such as <code>/auth/challenge</code>, which do not require authentication and have their own protection mechanisms - the limit is 60 requests per second for one IP address.</p><table tabindex="0"><thead><tr><th>Endpoint</th><th></th><th>req/s</th><th>req/min</th><th>req/h</th></tr></thead><tbody><tr><td>Others</td><td>POST/GET /*</td><td>10</td><td>30</td><td>120</td></tr></tbody></table><p>Related documents:</p><ul><li><a href="./limity.html">Limits</a></li></ul>',6)])])}const g=n(o,[["render",r]]);export{p as __pageData,g as default};
